import{_ as t,o,c as u,ag as q}from"./chunks/framework.-7YpjpW6.js";const c=JSON.parse('{"title":"第六章","description":"","frontmatter":{},"headers":[],"relativePath":"安乐回响-AI/6.md","filePath":"安乐回响-AI/6.md","lastUpdated":1776953967000}'),a={name:"安乐回响-AI/6.md"};function e(r,p,_,s,n,h){return o(),u("div",null,[...p[0]||(p[0]=[q('<h1 id="第六章" tabindex="-1">第六章 <a class="header-anchor" href="#第六章" aria-label="Permalink to &quot;第六章&quot;">​</a></h1><p>苏寒的目光落在那个全息影像上。</p><p>画面里，女人牵着小女孩的手，阳光从树叶间漏下来，洒在她们脸上。</p><p>&quot;你的妻子和女儿？&quot;</p><p>方执点了点头。声音很轻，像是怕惊扰了什么：&quot;她们走了很多年了。&quot;</p><p>停顿。窗外有车驶过的声音。</p><p>&quot;不过现在，她们在另一个地方。&quot;</p><p>苏寒的眉头皱起来：&quot;数字人格？&quot;</p><p>&quot;对。&quot;方执看着那个影像，&quot;我把她们带进了&#39;极乐世界&#39;。在那里和她们生活过一段时间。也告诉过她们真相。&quot;</p><p>他转过头，看向苏寒。</p><p>&quot;她们理解我。&quot;</p><hr><p>苏寒笑了一声。那笑声里没有温度。</p><p>&quot;理解你？&quot;他盯着方执，&quot;那不过是数据的回声。人死了就是死了，我们得学会放手。&quot;</p><p>&quot;你现在做的，不过是在亵渎他们。&quot;</p><p>方执看了他一会儿。然后忽然问：&quot;你听说过鸭子理论吗？&quot;</p><p>苏寒没接话。</p><p>方执的声音很慢，像是在讲一个很久以前的故事：</p><p>&quot;如果它看起来像鸭子，走起来像鸭子，叫起来也像鸭子——那它大概就是鸭子。&quot;</p><p>&quot;数字人格会思考，会记忆，会和人对话。会爱，会悲伤。&quot;他顿了顿，&quot;你说它只是回声。可你能保证十年前的你和现在的你，是同一个人吗？&quot;</p><p>他的嘴角扯出一个笑。</p><p>&quot;我们从出生开始，就一直在开着一艘忒修斯之船。身体在换，思想在换，记忆在消失又重建。&quot;</p><p>&quot;现在不过是换了一种形式。&quot;</p><hr><p>苏寒沉默了几秒。</p><p>&quot;那你考虑过故障吗？&quot;</p><p>他的声音低下来。</p><p>&quot;人格漂移。数字人格脱离肉体之后，会慢慢变得不像人。&quot;</p><p>&quot;还有复制。&quot;他盯着方执，&quot;如果系统里出现两个你、三个你、十个你，而且想法都不一样——你能接受吗？&quot;</p><p>方执摇了摇头。</p><p>&quot;人本来就会变。&quot;他说，&quot;年龄、经历、身体状况，都会改变人格。为什么你期待数字人格永远不变？&quot;</p><p>&quot;至于复制——&quot;他顿了顿，&quot;那只是技术问题。克隆技术可以立法禁止，复制意识当然也可以。你是技术员，应该知道数字人格的复制有多复杂。&quot;</p><hr><p>房间里安静下来。</p><p>只有空调的嗡鸣声。</p><p>苏寒叹了口气。</p><p>&quot;你想过没有，也许我们不是在解决问题。&quot;</p><p>&quot;我们只是在逃避。&quot;</p><p>&quot;你知道你现在的计划要付出多少代价吗？有多少风险？多少不可控的后果？&quot;</p><p>方执的目光落在桌上的全息影像上。</p><p>影像里的小女孩正拉着母亲的手笑。</p><p>他的声音低下来。</p><p>&quot;这些数字人已经死过一次了。&quot;</p><p>&quot;我不想让他们再死一次。&quot;</p><p>他抬起头。</p><p>&quot;停用他们、删除他们——那只是另一种形式的死亡。&quot;</p><p>&quot;我不在乎能不能成功。&quot;</p><p>停顿。</p><p>&quot;我只想让他们活着。&quot;</p><p>他看着苏寒。</p><p>&quot;无论用什么方式。&quot;</p><hr><p>苏寒没有说话。</p><p>方执忽然又开口：</p><p>&quot;其实，人类早就有某种形式的永生。&quot;</p><p>&quot;牛顿、爱因斯坦、霍金。&quot;</p><p>&quot;当有人读懂他们的理论，读者的思维就在和他们共鸣。&quot;</p><p>&quot;那一刻，他们就在那个人的脑海里活着。&quot;</p><p>他看向苏寒。</p><p>&quot;如果短暂的共鸣都能让一个人&#39;复活&#39;，那么一个持续运行、能够交流的赛博人格——为什么不算真正的永生？&quot;</p><p>他停顿了一下。</p><p>&quot;更何况，死亡本来就是文明最大的限制。&quot;</p><p>&quot;如果那些伟大的思想家能够一直活着，人类今天会走到哪里？&quot;</p><hr><p>苏寒正要开口。</p><p>门外突然传来急促的敲门声。</p><p>秘书推门冲进来，脸色发白。</p><p>&quot;方总！外面来了很多警车！把别墅包围了！&quot;</p><p>方执愣住。</p><p>他慢慢转过头，看向苏寒。</p><hr><p>苏寒笑了。</p><p>&quot;别执迷不悟了，方执。&quot;</p><p>&quot;我今天敢来这里，本来就冒了很大风险。&quot;</p><p>&quot;如果我被威胁，或者通讯设备被收走，我的AI助手会自动启动埋在外面的暗线。&quot;</p><p>&quot;现在警察应该已经拿到证据了。&quot;</p><p>他摊开手。</p><p>&quot;包括这里的设备、实验，还有你的服务器。&quot;</p><hr><p>门外的声音越来越嘈杂。</p><p>隐约能听见破门的声音。</p><p>方执沉默了很久。</p><p>最后，他轻轻叹了口气。</p><p>&quot;如果这里能让死去的人继续活着……&quot;</p><p>他的声音很低。</p><p>&quot;那现实又算什么？&quot;</p><p>他抬起头。眼神里有什么东西在燃烧。</p><p>&quot;我不承认这种只给少数人特权的现实。&quot;</p><p>他看着苏寒。</p><p>慢慢说出最后一句话：</p><p>&quot;如果有人愿意相信——&quot;</p><p>&quot;为什么幻觉不能成为现实？&quot;</p><hr><p>门被踹开。</p><p>警察冲进来。</p><p>方执没有动。</p><p>他只是站在那里，看着那个全息影像。</p><p>影像里的小女孩还在笑。</p><p>阳光透过树林洒下来。</p><p>一切都那么美好。</p><p>像是永远不会结束。</p><hr><p>一周后。</p><p>方执被警方起诉。</p><p>法院认定他严重侵害社会利益，犯下反社会罪。</p><p>那些所谓的&quot;极乐世界&quot;服务器被逐一关闭。</p><p>无数数字人格随之消失。</p><p>一切重回既定的轨道。</p><hr><p>但在服务器被关闭前的最后几秒。</p><p>苏寒用自己的权限，把方执那个能解决漂移问题的核心补丁包转移到了私人云端。</p><p>没有人知道。</p><p>也不会有人知道。</p><p>他只是在执行任务。</p><p>清理那些不该存在的东西。</p><p>但他留下了一个备份。</p><p>或许他想了解，到底是什么让方执变得如此疯狂。</p><p>又或许，他只是想留下一个火种。</p>',118)])])}const i=t(a,[["render",e]]);export{c as __pageData,i as default};
